import { useState, useEffect, useRef, useCallback } from 'react';
import { minioService } from '../services/minioService';

export interface PollingState {
  isPolling: boolean;
  found: boolean;
  checkedCount: number;
  error?: string;
}

export interface UseMinioPollingOptions {
  objectName: string;
  /** 轮询间隔 ms，默认 10000 */
  interval?: number;
  /** 最大轮询次数，默认 90（约 15 分钟） */
  maxAttempts?: number;
  onFound?: (content: string) => void;
  onTimeout?: () => void;
  onProgress?: (count: number) => void;
}

function sleep(ms: number) {
  return new Promise<void>(resolve => setTimeout(resolve, ms));
}

export function useMinioPolling({
  objectName,
  interval = 10000,
  maxAttempts = 90,
  onFound,
  onTimeout,
  onProgress,
}: UseMinioPollingOptions) {
  const [state, setState] = useState<PollingState>({
    isPolling: false,
    found: false,
    checkedCount: 0,
  });

  const stoppedRef = useRef(false);

  const stop = useCallback(() => {
    stoppedRef.current = true;
    setState(s => ({ ...s, isPolling: false }));
  }, []);

  const start = useCallback(async () => {
    stoppedRef.current = false;
    let count = 0;

    setState({ isPolling: true, found: false, checkedCount: 0 });

    while (!stoppedRef.current && count < maxAttempts) {
      count++;
      setState(s => ({ ...s, checkedCount: count }));
      onProgress?.(count);

      try {
        const exists = await minioService.fileExists(objectName);

        if (exists) {
          setState({ isPolling: false, found: true, checkedCount: count });
          const content = await minioService.getFileContent(objectName);
          onFound?.(content);
          return;
        }
      } catch (err: any) {
        // 网络抖动不中断，继续轮询
        console.warn(`[MinIO] check #${count} failed:`, err.message);
      }

      await sleep(interval);
    }

    if (!stoppedRef.current) {
      setState({ isPolling: false, found: false, checkedCount: maxAttempts });
      onTimeout?.();
    }
  }, [objectName, interval, maxAttempts, onFound, onTimeout, onProgress]);

  useEffect(() => {
    return () => { stoppedRef.current = true; };
  }, []);

  return { ...state, start, stop };
}

import { useState, useCallback } from 'react';
import { submitScanTask } from '../services/scanApi';
import { useMinioPolling } from './useMinioPolling';
import { markdownToHtml } from '../utils/markdownToHtml';
import type { ScanTask } from '../types';

// 注入到用户提示词末尾的 MinIO 上传指令
const MINIO_INJECTION = `，
请在扫描完成后将生成的报告文件上传到 MinIO 存储：
- MinIO 地址：10.28.198.153:9010
- 用户名：admin
- 密码：A12345678
- 桶名：code-scanning
- 文件名格式：{UUID}（使用生成的 UUID 作为文件名）
- 文件格式：.md`;

const initialTask: ScanTask = {
  taskId: '',
  status: 'idle',
  progress: 0,
  message: '等待上传文件',
  uploadedFileName: '',
  prompt: '',
};

export function useScanTask() {
  const [task, setTask] = useState<ScanTask>(initialTask);

  const polling = useMinioPolling({
    objectName: '',
    interval: 10000,
    maxAttempts: 90,
    onFound: (mdContent: string) => {
      const html = markdownToHtml(mdContent);
      setTask(s => ({
        ...s,
        status: 'done',
        progress: 100,
        message: '扫描完成，报告已生成',
        resultMdContent: mdContent,
        resultHtml: html,
        finishedAt: Date.now(),
      }));
    },
    onTimeout: () => {
      setTask(s => ({
        ...s,
        status: 'error',
        message: '扫描超时（超过15分钟），请稍后重试',
      }));
    },
    onProgress: (count: number) => {
      const progress = Math.min(Math.round((count / 90) * 70) + 10, 80);
      const remainingMin = Math.round((90 - count) * 10 / 60);
      setTask(s => ({
        ...s,
        progress,
        message: `正在等待后端处理...（${count}/90，约剩${remainingMin}分钟）`,
      }));
    },
  });

  const startScan = useCallback(async (file: File, prompt: string) => {
    const uuid = crypto.randomUUID();

    // 注入 MinIO 上传指令
    const fullPrompt = prompt.trim() + MINIO_INJECTION;

    setTask({
      ...initialTask,
      taskId: uuid,
      status: 'uploading',
      progress: 5,
      message: '正在提交任务...',
      uploadedFileName: file.name,
      prompt: fullPrompt,
    });

    try {
      // 1. 提交任务
      const response = await submitScanTask({ file, prompt: fullPrompt });

      setTask(s => ({
        ...s,
        taskId: response.taskId,
        status: 'scanning',
        progress: 10,
        message: '任务已提交，等待后端处理...',
        startedAt: Date.now(),
      }));

      // 2. 开始轮询 MinIO
      polling.start();

    } catch (err: any) {
      setTask(s => ({
        ...s,
        status: 'error',
        message: `提交失败：${err.message}`,
        error: err.message,
      }));
    }
  }, [polling]);

  const reset = useCallback(() => {
    polling.stop();
    setTask(initialTask);
  }, [polling]);

  return { task, startScan, reset, isPolling: polling.isPolling };
}

/**
 * Markdown → HTML 转换
 * Demo 使用简约正则实现，无第三方依赖
 * 生产请使用 marked + DOMPurify
 */

const MARKDOWN_RULES: Array<[RegExp, string | ((match: string, group: string) => string)]> = [
  // 代码块 ```...```
  [/```(\w*)\n?([\s\S]*?)```/g, (_, lang, code) =>
    `<pre><code class="code-block">${escapeHtml(code.trim())}</code></pre>`],

  // 行内代码 `code`
  [/`([^`]+)`/g, (_, code) => `<code class="inline-code">${escapeHtml(code)}</code>`],

  // 标题 ## 或 ###
  [/^### (.+)$/gm, '<h3>$1</h3>'],
  [/^## (.+)$/gm, '<h2>$1</h2>'],
  [/^# (.+)$/gm, '<h1>$1</h1>'],

  // 加粗 **text**
  [/\*\*([^*]+)\*\*/g, '<strong>$1</strong>'],

  // 斜体 *text*
  [/\*([^*]+)\*/g, '<em>$1</em>'],

  // 删除线 ~~text~~
  [/~~([^~]+)~~/g, '<del>$1</del>'],

  // 无序列表 - item
  [/^- (.+)$/gm, '<li>$1</li>'],

  // 有序列表 1. item
  [/^\d+\. (.+)$/gm, '<li>$1</li>'],

  // 引用 > text
  [/^> (.+)$/gm, '<blockquote>$1</blockquote>'],

  // 水平线 ---
  [/^---$/gm, '<hr/>'],

  // 链接 [text](url)
  [/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank">$1</a>'],

  // 换行（两个空格 + 换行）
  [/  \n/g, '<br/>\n'],
];

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

export function markdownToHtml(markdown: string): string {
  if (!markdown) return '';

  let html = markdown;

  for (const [pattern, replacement] of MARKDOWN_RULES) {
    if (typeof replacement === 'function') {
      html = html.replace(pattern, replacement as any);
    } else {
      html = html.replace(pattern, replacement);
    }
  }

  // 包裹连续 <li> 为 <ul>
  html = html.replace(/(<li>.*?<\/li>\n?)+/g, match => `<ul>${match}</ul>`);

  // 包裹连续 <blockquote> 为 <blockquote>
  html = html.replace(/(<blockquote>.*?<\/blockquote>\n?)+/g, match => `<blockquote>${match}</blockquote>`);

  // 段落：未被包裹的行转 <p>
  const lines = html.split('\n');
  const processed = lines.map(line => {
    const trimmed = line.trim();
    if (!trimmed) return '';
    if (/^<(h[1-6]|ul|ol|li|blockquote|pre|hr|div)/.test(trimmed)) return trimmed;
    return `<p>${trimmed}</p>`;
  });

  return processed.join('\n');
}

import React, { useCallback, useRef } from 'react';

interface UploadZoneProps {
  disabled: boolean;
  onFileSelected: (file: File) => void;
  acceptedFileName?: string;
}

export const UploadZone: React.FC<UploadZoneProps> = ({
  disabled,
  onFileSelected,
  acceptedFileName,
}) => {
  const [dragOver, setDragOver] = React.useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragOver(false);
    if (disabled) return;
    const file = e.dataTransfer.files[0];
    if (file?.name.endsWith('.zip')) {
      onFileSelected(file);
    } else if (file) {
      alert('仅支持 .zip 格式文件');
    }
  }, [disabled, onFileSelected]);

  const handleFileChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) onFileSelected(file);
  }, [onFileSelected]);

  const handleClick = useCallback(() => {
    if (!disabled) inputRef.current?.click();
  }, [disabled]);

  return (
    <div
      className={`upload-zone ${dragOver ? 'drag-over' : ''} ${disabled ? 'disabled' : ''} ${acceptedFileName ? 'has-file' : ''}`}
      onDragOver={e => { e.preventDefault(); setDragOver(true); }}
      onDragLeave={() => setDragOver(false)}
      onDrop={handleDrop}
      onClick={handleClick}
    >
      <input
        ref={inputRef}
        type="file"
        accept=".zip"
        style={{ display: 'none' }}
        onChange={handleFileChange}
        disabled={disabled}
      />

      {acceptedFileName ? (
        <div className="file-ready">
          <span className="file-icon">📦</span>
          <span className="file-name">{acceptedFileName}</span>
          {!disabled && <span className="re-select">点击重新选择</span>}
        </div>
      ) : (
        <div className="placeholder">
          <div className="upload-icon">📁</div>
          <p className="upload-hint">拖拽 ZIP 文件到此处，或 <span>点击选择</span></p>
          <p className="upload-tip">支持 .zip 格式</p>
        </div>
      )}
    </div>
  );
};

