.code-scanner {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  max-width: 760px;
  margin: 0 auto;
  padding: 24px;
  color: #1e293b;
}

/* --- Header --- */
.scanner-header { margin-bottom: 20px; }
.scanner-title {
  font-size: 22px;
  font-weight: 700;
  margin: 0 0 4px;
}
.scanner-subtitle {
  font-size: 13px;
  color: #64748b;
  margin: 0;
}

/* --- 步骤指示器 --- */
.step-indicator {
  display: flex;
  align-items: center;
  margin-bottom: 24px;
}
.step-item {
  display: flex;
  align-items: center;
  gap: 6px;
}
.step-circle {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 600;
  flex-shrink: 0;
  transition: all 0.2s;
}
.step-item.active .step-circle {
  background: #3b82f6;
  color: #fff;
}
.step-item.done .step-circle {
  background: #22c55e;
  color: #fff;
}
.step-item.pending .step-circle {
  background: #e2e8f0;
  color: #94a3b8;
}
.step-label {
  font-size: 13px;
  font-weight: 500;
}
.step-item.active .step-label { color: #3b82f6; }
.step-item.done .step-label { color: #22c55e; }
.step-item.pending .step-label { color: #94a3b8; }
.step-connector {
  width: 40px;
  height: 2px;
  background: #e2e8f0;
  margin: 0 4px;
}
.step-item.done + .step-item .step-connector,
.step-item.done .step-connector {
  background: #22c55e;
}

/* --- 上传区 --- */
.upload-zone {
  border: 2px dashed #cbd5e1;
  border-radius: 12px;
  padding: 32px;
  text-align: center;
  cursor: pointer;
  transition: all 0.2s;
  margin-bottom: 16px;
  background: #f8fafc;
}
.upload-zone:hover { border-color: #3b82f6; background: #eff6ff; }
.upload-zone.drag-over { border-color: #3b82f6; background: #dbeafe; }
.upload-zone.disabled { opacity: 0.6; cursor: not-allowed; }
.upload-zone.has-file { border-color: #22c55e; background: #f0fdf4; border-style: solid; }

.placeholder .upload-icon { font-size: 36px; margin-bottom: 8px; }
.upload-hint { font-size: 14px; margin: 0 0 4px; color: #475569; }
.upload-hint span { color: #3b82f6; font-weight: 500; cursor: pointer; }
.upload-tip { font-size: 12px; color: #94a3b8; margin: 0; }

.file-ready { display: flex; align-items: center; gap: 8px; justify-content: center; }
.file-icon { font-size: 24px; }
.file-name { font-size: 14px; font-weight: 600; color: #166534; }
.re-select { font-size: 12px; color: #64748b; }

/* --- 提示词 --- */
.prompt-input-wrapper { margin-bottom: 16px; }
.prompt-label {
  font-size: 13px;
  font-weight: 600;
  color: #475569;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 4px;
}
.prompt-textarea {
  width: 100%;
  box-sizing: border-box;
  padding: 12px;
  border: 1.5px solid #cbd5e1;
  border-radius: 8px;
  font-size: 14px;
  line-height: 1.6;
  resize: vertical;
  font-family: inherit;
  transition: border-color 0.2s;
  background: #fff;
}
.prompt-textarea:focus { outline: none; border-color: #3b82f6; }
.prompt-textarea:disabled { background: #f1f5f9; cursor: not-allowed; }

.injection-hint {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 6px;
  padding: 6px 10px;
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  border-radius: 6px;
  font-size: 12px;
  color: #15803d;
}
.hint-icon { }

/* --- 操作按钮 --- */
.action-bar {
  display: flex;
  gap: 12px;
  margin-bottom: 16px;
}
.btn-primary {
  flex: 1;
  padding: 12px 24px;
  background: #3b82f6;
  color: #fff;
  border: none;
  border-radius: 8px;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s;
}
.btn-primary:hover { background: #2563eb; }
.btn-primary:disabled { background: #94a3b8; cursor: not-allowed; }
.btn-secondary {
  padding: 12px 20px;
  background: #fff;
  color: #475569;
  border: 1.5px solid #cbd5e1;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
}
.btn-secondary:hover { background: #f8fafc; }

/* --- 扫描状态 --- */
.scan-status {
  padding: 16px;
  background: #f8fafc;
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  margin-bottom: 16px;
}
.status-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 10px;
}
.status-icon { font-size: 18px; }
.status-label { font-size: 14px; font-weight: 600; }
.task-id {
  font-size: 12px;
  color: #94a3b8;
  font-family: monospace;
  margin-left: 4px;
}
