  align-items: center;
  gap: 5px;
  font-size: 12px;
  color: #8b5cf6;
}
.dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: #8b5cf6;
  animation: pulse 1.4s infinite;
}
@keyframes pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.4; transform: scale(0.85); }
}

.progress-wrapper {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}
.progress-bar {
  flex: 1;
  height: 6px;
  background: #e2e8f0;
  border-radius: 3px;
  overflow: hidden;
}
.progress-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.5s ease;
}
.progress-text { font-size: 12px; color: #64748b; min-width: 36px; }
.status-message { font-size: 13px; color: #475569; margin: 0 0 8px; }
.status-footer { display: flex; align-items: center; justify-content: space-between; }
.elapsed { font-size: 12px; color: #94a3b8; }
.btn-cancel {
  font-size: 12px;
  color: #ef4444;
  background: none;
  border: 1px solid #fecaca;
  border-radius: 4px;
  padding: 3px 10px;
  cursor: pointer;
}
.btn-cancel:hover { background: #fef2f2; }
.error-detail {
  margin-top: 8px;
  font-size: 12px;
  color: #ef4444;
  padding: 6px 10px;
  background: #fef2f2;
  border-radius: 4px;
  font-family: monospace;
}

/* --- 错误卡片 --- */
.error-card {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 12px 16px;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 8px;
  color: #dc2626;
  font-size: 14px;
  margin-bottom: 16px;
}

/* --- 结果展示 --- */
.result-viewer {
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  overflow: hidden;
}
.result-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 16px;
  background: #f8fafc;
  border-bottom: 1px solid #e2e8f0;
}
.result-title { font-size: 13px; font-weight: 600; color: #475569; }
.toolbar-actions { display: flex; gap: 8px; }
.btn-toolbar {
  font-size: 12px;
  padding: 4px 10px;
  background: #fff;
  border: 1px solid #cbd5e1;
  border-radius: 5px;
  cursor: pointer;
  color: #475569;
}
.btn-toolbar:hover { background: #f1f5f9; }

.report-content {
  padding: 20px;
  max-height: 600px;
  overflow-y: auto;
}

/* --- Markdown 渲染样式 --- */
.markdown-body h1 { font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin: 20px 0 12px; }
.markdown-body h2 { font-size: 17px; border-bottom: 1px solid #e2e8f0; padding-bottom: 6px; margin: 18px 0 10px; }
.markdown-body h3 { font-size: 15px; margin: 16px 0 8px; }
.markdown-body p { margin: 8px 0; line-height: 1.7; }
.markdown-body ul, .markdown-body ol { margin: 8px 0; padding-left: 24px; }
.markdown-body li { margin: 4px 0; line-height: 1.6; }
.markdown-body blockquote {
  margin: 10px 0;
  padding: 8px 14px;
  background: #f8fafc;
  border-left: 3px solid #cbd5e1;
  color: #475569;
}
.markdown-body .code-block {
  background: #1e293b;
  color: #e2e8f0;
  padding: 14px;
  border-radius: 8px;
  overflow-x: auto;
  font-family: 'Fira Code', 'Consolas', monospace;
  font-size: 13px;
  display: block;
  margin: 10px 0;
  white-space: pre;
}
.markdown-body .inline-code {
  background: #f1f5f9;
